-- Tabla de prueba con formato solicitado
-- Fuente: LISTA DE REGISTROS DEL SHEETS.tsv

DROP TABLE IF EXISTS public.registros_sheets_prueba;

CREATE TABLE public.registros_sheets_prueba (
  id BIGSERIAL PRIMARY KEY,
  "Fecha Empaquetado" TEXT NOT NULL,
  "Fecha Almacen09" TEXT NOT NULL,
  "CODIGO PRODUCTO" TEXT NOT NULL,
  "PRODUCTO" TEXT NOT NULL,
  "CANTIDAD" TEXT NOT NULL,
  "ENTREGADO A" TEXT NOT NULL,
  "NUMERO REGISTRO" TEXT NOT NULL,
  "RESPONSABLE" TEXT NOT NULL,
  "SEDE" TEXT NOT NULL,
  "NUMERO DE LOTE" TEXT NOT NULL
);

;

CREATE INDEX idx_registros_sheets_producto ON public.registros_sheets_prueba ("PRODUCTO");
CREATE INDEX idx_registros_sheets_registro ON public.registros_sheets_prueba ("NUMERO REGISTRO");
CREATE INDEX idx_registros_sheets_lote ON public.registros_sheets_prueba ("NUMERO DE LOTE");

SELECT COUNT(*) AS total_filas FROM public.registros_sheets_prueba;

SELECT
  pg_size_pretty(pg_relation_size('public.registros_sheets_prueba')) AS table_only,
  pg_size_pretty(pg_indexes_size('public.registros_sheets_prueba')) AS indexes_only,
  pg_size_pretty(pg_total_relation_size('public.registros_sheets_prueba')) AS total_with_indexes;

SELECT
  pg_relation_size('public.registros_sheets_prueba') AS table_bytes,
  pg_indexes_size('public.registros_sheets_prueba') AS index_bytes,
  pg_total_relation_size('public.registros_sheets_prueba') AS total_bytes;
